import "../styles/events.css";
import Dropdown from "../components/Dropdown";

export default function EventTable({
                                       events = [],
                                       loading = false,
                                       error = "",
                                       showClub = true,
                                       isPrivileged = false,
                                       onEdit,
                                       onDelete,
    onTagClick
                                   }) {

    /* =====================
       EVENT STATUS
    ===================== */
    const getEventStatus = (ev) => {
        if (!ev?.startAt) return "UPCOMING";

        const now = new Date();
        const start = new Date(ev.startAt);
        const end = ev.endAt
            ? new Date(ev.endAt)
            : new Date(start.getTime() + 2 * 60 * 60 * 1000);

        if (now >= start && now <= end) return "LIVE";
        if (now > end) return "ENDED";
        return "UPCOMING";
    };

    if (loading) return <p className="muted">Loading…</p>;
    if (error) return <p className="error">{error}</p>;

    if (!events.length) {
        return (
            <div className="muted" style={{ padding: 20, textAlign: "center" }}>
                No events to display.
            </div>
        );
    }

    return (
        <div className="events-table">
            <div className={`events-header ${isPrivileged ? "has-actions" : ""}`}>

                <div>#</div>
                <div>Event</div>
                {showClub && <div className="club-col">Club</div>}
                <div>Status</div>
                <div>Avg. Rating</div>
                {isPrivileged && <div >Visibility</div>}
                {isPrivileged && <div className="actions-col">Actions</div>}
            </div>

            {events.map((ev, i) => {
                const status = getEventStatus(ev);

                return (
                    <div
                        key={ev.id}
                        className={`events-row clickable ${
                            isPrivileged ? "has-actions" : ""
                        }`}
                        onClick={() =>
                            (window.location.hash = `#/events/${ev.id}`)
                        }
                    >
                        <div className="rank">{i + 1}</div>

                        <div className="event-main">
                            <div className="event-title">{ev.title}</div>

                            <div className="event-meta">
                                {ev.startAt
                                    ? new Date(ev.startAt).toLocaleString()
                                    : "TBA"}
                                {ev.location && ` · ${ev.location}`}
                            </div>

                            <div className="event-tags">
                                {ev.tags?.map((t) => {
                                    const tagName = typeof t === "string" ? t : t.name;

                                    return (
                                        <span
                                            key={tagName}
                                            className="event-tag clickable"
                                            onClick={(e) => {
                                                e.stopPropagation();   // 🔑 prevent row click
                                                onTagClick?.(tagName);
                                            }}
                                        >
                {tagName}
            </span>
                                    );
                                })}
                            </div>

                        </div>

                        {showClub && (
                            <div>
                                {ev.clubId ? (
                                    <span
                                        className="event-club-badge"
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            window.location.hash = `#/clubs/${ev.clubId}`;
                                        }}
                                    >
                                        {ev.clubName}
                                    </span>
                                ) : (
                                    <span className="muted">Independent</span>
                                )}
                            </div>
                        )}

                        <div className={`event-status ${status.toLowerCase()}`}>
                            {status}
                        </div>

                        <div className="event-rating-inline">
                            {ev.ratingCount > 0 ? (
                                <>
                                    <span className="star">★</span>
                                    {ev.averageRating.toFixed(1)}
                                    <span className="rating-count">
                                        ({ev.ratingCount})
                                    </span>
                                </>
                            ) : (
                                <span className="muted">No ratings</span>
                            )}
                        </div>

                        {isPrivileged && (
                            <td>
                                <span
                                    className={`visibility-badge ${
                                        ev.visibility === "PUBLIC"
                                ? "public"
                                : "restricted"
                        }`}
                    >
                        {ev.visibility === "PUBLIC"
                            ? "Public"
                            : "Club Members"}
                    </span>
                            </td>
                        )}

                        {isPrivileged && (
                            <div className="actions">
                                <Dropdown
                                    onEdit={() => onEdit(ev)}
                                    onDelete={() => onDelete(ev)}
                                />
                            </div>
                        )}
                    </div>
                );
            })}
        </div>
    );
}
